<?php\n\nnamespace Database\\Seeders;\n\nuse Illuminate\\Database\\Seeder;\nuse Illuminate\\Support\\Facades\\DB;\nuse Illuminate\\Support\\Facades\\Hash;\nuse App\\Models\\User;\n\nclass DatabaseSeeder extends Seeder\n{\n    public function run(): void\n    {\n        // Create admin user\n        User::firstOrCreate(\n            ['email' => 'admin@smmelite.com'],\n            [\n                'name' => 'Administrator',\n                'password' => Hash::make('AdminPassword123!'),\n                'funds' => 0,\n                'status' => 'active',\n                'is_admin' => true,\n            ]\n        );\n\n        // Create demo user\n        User::firstOrCreate(\n            ['email' => 'demo@smmelite.com'],\n            [\n                'name' => 'Demo User',\n                'password' => Hash::make('DemoPassword123!'),\n                'funds' => 5000,\n                'status' => 'active',\n                'is_admin' => false,\n            ]\n        );\n\n        // Create categories\n        $categories = [\n            ['name' => 'Instagram', 'icon' => 'camera', 'color' => '#e4405f'],\n            ['name' => 'Facebook', 'icon' => 'facebook', 'color' => '#1877f2'],\n            ['name' => 'Twitter', 'icon' => 'twitter', 'color' => '#1da1f2'],\n            ['name' => 'TikTok', 'icon' => 'music', 'color' => '#000000'],\n            ['name' => 'YouTube', 'icon' => 'play-circle', 'color' => '#ff0000'],\n            ['name' => 'LinkedIn', 'icon' => 'linkedin', 'color' => '#0a66c2'],\n        ];\n\n        foreach ($categories as $category) {\n            DB::table('categories')->insertOrIgnore(\n                array_merge($category, ['status' => 'active', 'created_at' => now(), 'updated_at' => now()])\n            );\n        }\n\n        echo \"✓ Database seeded successfully!\\n\";\n    }\n}\n